INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('06b883e6-1a46-57e1-b78c-e4537a05174e', '8e57d228-2375-4684-9b15-7e73584141b6', 'Can you ___ me some water, please?', '可以請你幫我拿點水嗎？', 'get', 'tell', 'look', 'sing', '表示「取得」或「拿取」的意思。', 'Get it! (拿到它)'),
('a48a6994-3cc3-59d5-9711-0da3ab89183a', 'd99f5952-91d8-41d5-8a1c-267609e39a20', 'The seminar was ___ the impact of social media on teenagers.', '這場研討會是關於社群媒體對青少年的影響。', 'about', 'during', 'across', 'between', '表示主題或內容 (關於)', 'about + [主題] → 關於某事'),
('2278850f-f253-5d6a-926d-512e86390552', '689e8620-8af8-45d0-b3cc-53eb54374dfc', '___ is my friend, Tim.', '這是我朋友 Tim。', 'This', 'He', 'It', 'Someone', 'This 在此為代名詞，用於向人介紹身邊的人。', 'This (這) → 介紹身邊的人或事物時使用。'),
('a994a63e-e00f-5300-9779-100af4648aea', '6f473860-59ac-4c93-809a-155f5d561a5f', 'The girl ___ long hair looks very beautiful.', '留著長髮的女孩看起來非常漂亮。', 'with', 'for', 'in', 'on', '表示「具有...的特徵」', '帶著某種特徵 → with'),
('4992ceb8-88b1-5cae-80b8-46d4c65a0826', 'fbf1bc22-9ad9-4a87-9256-4a0fc5e9a81b', 'I am ___ sure if I can attend the meeting tomorrow.', '我不確定明天是否能參加會議。', 'not', 'very', 'always', 'almost', '表示否定 (Negative marker)', '用來否定狀態或感覺。');
